INSERT INTO settings (key, value, data_type, description, is_editable) VALUES ('showcase_projects_json', '[{"id": "sylhet-retail-pos", "slug": "sylhet-retail-pos", "title": {"en": "Retail POS System", "bn": "রিটেইল POS সিস্টেম"}, "client": {"en": "Sylhet Retail Shop", "bn": "সিলেট রিটেইল শপ"}, "category": {"en": "POS", "bn": "POS"}, "technologies": ["React", "Node.js", "PostgreSQL", "Thermal Print"], "problem": {"en": "Manual billing caused errors and slow checkout.", "bn": "ম্যানুয়াল বিলিং-এ ভুল ও ধীর চেকআউট।"}, "solution": {"en": "Custom POS with inventory sync and receipt printing.", "bn": "ইনভেন্টরি সিঙ্ক ও রসিদ প্রিন্ট সহ কাস্টম POS।"}, "result": {"en": "50% faster billing, zero calculation errors.", "bn": "৫০% দ্রুত বিলিং, শূন্য হিসাব ভুল।"}, "year": 2025, "sortOrder": 0, "featured": true, "image": "https://placehold.co/1920x1080/webp?text=Retail%20POS%20System", "images": ["https://placehold.co/1920x1080/webp?text=Retail%20POS%20System%201", "https://placehold.co/1920x1080/webp?text=Retail%20POS%20System%202"]}, {"id": "clinic-hms", "slug": "clinic-hms", "title": {"en": "Hospital Management System", "bn": "হাসপাতাল ম্যানেজমেন্ট সিস্টেম"}, "client": {"en": "Local Clinic, Sylhet", "bn": "স্থানীয় ক্লিনিক, সিলেট"}, "category": {"en": "Healthcare", "bn": "স্বাস্থ্য"}, "technologies": ["Next.js", "FastAPI", "PostgreSQL"], "problem": {"en": "Paper records and delayed billing.", "bn": "কাগজের রেকর্ড ও বিলিং বিলম্ব।"}, "solution": {"en": "Digital patient records and automated billing.", "bn": "ডিজিটাল রোগী রেকর্ড ও অটো বিলিং।"}, "result": {"en": "100% digital records, 3x faster billing.", "bn": "১০০% ডিজিটাল রেকর্ড, ৩x দ্রুত বিলিং।"}, "year": 2024, "sortOrder": 1, "featured": true, "image": "https://placehold.co/1920x1080/webp?text=Hospital%20Management%20System", "images": ["https://placehold.co/1920x1080/webp?text=Hospital%20Management%20System%201", "https://placehold.co/1920x1080/webp?text=Hospital%20Management%20System%202"]}, {"id": "ecommerce-ai-chatbot", "slug": "ecommerce-ai-chatbot", "title": {"en": "E-Commerce + AI Chatbot", "bn": "ই-কমার্স + AI চ্যাটবট"}, "client": {"en": "E-Commerce Brand", "bn": "ই-কমার্স ব্র্যান্ড"}, "category": {"en": "Web + AI", "bn": "ওয়েব + AI"}, "technologies": ["Next.js", "OpenAI API", "Vercel"], "problem": {"en": "No online presence, losing customers.", "bn": "অনলাইনে উপস্থিতি নেই, গ্রাহক হারানো।"}, "solution": {"en": "Full storefront with 24/7 AI customer support.", "bn": "২৪/৭ AI সাপোর্ট সহ সম্পূর্ণ স্টোরফ্রন্ট।"}, "result": {"en": "200% more leads in 3 months.", "bn": "৩ মাসে ২০০% বেশি লিড।"}, "year": 2025, "sortOrder": 2, "featured": true, "image": "https://placehold.co/1920x1080/webp?text=E-Commerce%20%2B%20AI%20Chatbot", "images": ["https://placehold.co/1920x1080/webp?text=E-Commerce%20%2B%20AI%20Chatbot%201", "https://placehold.co/1920x1080/webp?text=E-Commerce%20%2B%20AI%20Chatbot%202"]}]', 'json', 'Project gallery showcase', true) ON CONFLICT (key) DO NOTHING;
